#include <iostream>
#include <vector>

using namespace std;

const int MAXN = 400005;
int ch[MAXN][2], fa[MAXN], rev[MAXN], val[MAXN], min_node[MAXN];
int U[MAXN], V[MAXN], prv[MAXN], bit[MAXN];
int M, N, Q;

// Update the node with the minimum edge index in its splay subtree
inline void pushup(int x) {
    min_node[x] = x;
    if (ch[x][0] && val[min_node[ch[x][0]]] < val[min_node[x]]) min_node[x] = min_node[ch[x][0]];
    if (ch[x][1] && val[min_node[ch[x][1]]] < val[min_node[x]]) min_node[x] = min_node[ch[x][1]];
}

// Push down the lazy reversal tag
inline void pushdown(int x) {
    if (rev[x]) {
        swap(ch[x][0], ch[x][1]);
        if (ch[x][0]) rev[ch[x][0]] ^= 1;
        if (ch[x][1]) rev[ch[x][1]] ^= 1;
        rev[x] = 0;
    }
}

inline bool is_root(int x) { 
    return ch[fa[x]][0] != x && ch[fa[x]][1] != x; 
}

inline void rotate(int x) {
    int y = fa[x], z = fa[y], k = (ch[y][1] == x);
    if (!is_root(y)) ch[z][ch[z][1] == y] = x;
    fa[x] = z;
    ch[y][k] = ch[x][k ^ 1];
    if (ch[x][k ^ 1]) fa[ch[x][k ^ 1]] = y;
    ch[x][k ^ 1] = y;
    fa[y] = x;
    pushup(y); pushup(x);
}

int stk[MAXN];
inline void splay(int x) {
    int top = 0, curr = x;
    stk[++top] = curr;
    while (!is_root(curr)) {
        curr = fa[curr];
        stk[++top] = curr;
    }
    while (top) pushdown(stk[top--]);
    while (!is_root(x)) {
        int y = fa[x], z = fa[y];
        if (!is_root(y)) {
            if ((ch[y][1] == x) ^ (ch[z][1] == y)) rotate(x);
            else rotate(y);
        }
        rotate(x);
    }
}

inline void access(int x) {
    for (int y = 0; x; y = x, x = fa[x]) {
        splay(x);
        ch[x][1] = y;
        pushup(x);
    }
}

inline void makeroot(int x) { 
    access(x); 
    splay(x); 
    rev[x] ^= 1; 
}

inline int findroot(int x) {
    access(x); 
    splay(x); 
    pushdown(x);
    while (ch[x][0]) { 
        x = ch[x][0]; 
        pushdown(x); 
    }
    splay(x);
    return x;
}

inline void split(int x, int y) { 
    makeroot(x); 
    access(y); 
    splay(y); 
}

inline void safe_link(int x, int y) { 
    makeroot(x); 
    fa[x] = y; 
}

inline void safe_cut(int x, int y) { 
    split(x, y); 
    ch[y][0] = fa[x] = 0; 
    pushup(y); 
}

// Fenwick Tree Operations
inline void add(int idx, int v) { 
    for (; idx <= M + 1; idx += idx & -idx) bit[idx] += v; 
}

inline int query(int idx) { 
    int sum = 0; 
    for (; idx > 0; idx -= idx & -idx) sum += bit[idx]; 
    return sum; 
}

struct Query { 
    int L, id; 
};

int main() {
    // Fast I/O
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int T;
    if (!(cin >> T)) return 0;

    while (T--) {
        cin >> N >> M >> Q;
        vector<vector<Query>> queries(M + 1);

        for (int i = 1; i <= M; ++i) {
            cin >> U[i] >> V[i];
            bit[i] = 0;
        }
        bit[M + 1] = 0;

        for (int i = 0; i < Q; ++i) {
            int L, R;
            cin >> L >> R;
            queries[R].push_back({L, i});
        }

        // Initialize Link-Cut Tree nodes
        for (int i = 1; i <= N + M; ++i) {
            ch[i][0] = ch[i][1] = fa[i] = rev[i] = 0;
            // Vertices have infinite weight, edge nodes have weight = edge index
            val[i] = (i <= N) ? 1e9 : (i - N);
            min_node[i] = i;
        }

        // Process edges iteratively
        for (int i = 1; i <= M; ++i) {
            int u = U[i], v = V[i];

            // Self-loop: trivially useless
            if (u == v) { 
                prv[i] = i; 
                continue; 
            }

            makeroot(u);
            if (findroot(v) == u) {
                // A cycle is formed, find the earliest edge in this cycle
                split(u, v);
                int min_nd = min_node[v];
                int j = val[min_nd];
                prv[i] = j;

                // Cut the oldest edge and link the new one
                safe_cut(U[j], N + j); 
                safe_cut(V[j], N + j);
                safe_link(u, N + i); 
                safe_link(v, N + i);
            } else {
                // No cycle formed
                prv[i] = 0;
                safe_link(u, N + i); 
                safe_link(v, N + i);
            }
        }

        // Answer offline queries using the Fenwick Tree
        vector<int> ans(Q);
        for (int i = 1; i <= M; ++i) {
            add(prv[i] + 1, 1);
            for (auto& q : queries[i]) {
                ans[q.id] = N - query(q.L) + q.L - 1;
            }
        }

        // Print results for this test case
        for (int i = 0; i < Q; ++i) {
            cout << ans[i] << "\n";
        }
    }
    return 0;
}

