    const U = new Int32Array(200005), V = new Int32Array(200005);

    const q_head = new Int32Array(200005), q_next = new Int32Array(200005);
    const q_L = new Int32Array(200005), q_id = new Int32Array(200005);

    function pushup(x) {
        let mn = x, c0 = ch0[x];
        if (c0 && val[min_node[c0]] < val[mn]) mn = min_node[c0];
        let c1 = ch1[x];
        if (c1 && val[min_node[c1]] < val[mn]) mn = min_node[c1];
        min_node[x] = mn;
    }

    function pushdown(x) {
        if (rev[x]) {
            let tmp = ch0[x]; ch0[x] = ch1[x]; ch1[x] = tmp;
            if (ch0[x]) rev[ch0[x]] ^= 1;
            if (ch1[x]) rev[ch1[x]] ^= 1;
            rev[x] = 0;
        }
    }

    function is_root(x) { return ch0[fa[x]] !== x && ch1[fa[x]] !== x; }

    function rotate(x) {
        let y = fa[x], z = fa[y], k = (ch1[y] === x) ? 1 : 0;
        if (!is_root(y)) { if (ch1[z] === y) ch1[z] = x; else ch0[z] = x; }
        fa[x] = z;
        if (k === 1) { ch1[y] = ch0[x]; if (ch0[x]) fa[ch0[x]] = y; ch0[x] = y; } 
        else { ch0[y] = ch1[x]; if (ch1[x]) fa[ch1[x]] = y; ch1[x] = y; }
        fa[y] = x; pushup(y); pushup(x);
    }

    function splay(x) {
        let top = 0, curr = x;
        stk[++top] = curr;
        while (!is_root(curr)) { curr = fa[curr]; stk[++top] = curr; }
        while (top > 0) pushdown(stk[top--]);
        while (!is_root(x)) {
            let y = fa[x], z = fa[y];
            if (!is_root(y)) { if ((ch1[y] === x) ^ (ch1[z] === y)) rotate(x); else rotate(y); }
            rotate(x);
        }
    }

    function access(x) {
        for (let y = 0; x !== 0; y = x, x = fa[x]) {
            splay(x); ch1[x] = y; pushup(x);
        }
    }

    function makeroot(x) { access(x); splay(x); rev[x] ^= 1; }
    function findroot(x) {
        access(x); splay(x); pushdown(x);
        while (ch0[x] !== 0) { x = ch0[x]; pushdown(x); }
        splay(x); return x;
    }

    function split(x, y) { makeroot(x); access(y); splay(y); }
    function safe_link(x, y) { makeroot(x); fa[x] = y; }
    function safe_cut(x, y) { split(x, y); ch0[y] = 0; fa[x] = 0; pushup(y); }

    let out = [];

    for (let t = 0; t < T; t++) {
        let N = readInt(), M = readInt(), Q = readInt();

        for (let i = 1; i <= M; i++) {
            U[i] = readInt(); V[i] = readInt();
            q_head[i] = bit[i] = 0;
        }
        bit[M + 1] = 0;

        let q_cnt = 0;
        for (let i = 0; i < Q; i++) {
            let L = readInt(), R = readInt();
            q_cnt++; q_L[q_cnt] = L; q_id[q_cnt] = i;
            q_next[q_cnt] = q_head[R]; q_head[R] = q_cnt;
        }

        for (let i = 1; i <= N + M; i++) {
            ch0[i] = ch1[i] = fa[i] = rev[i] = 0;
            val[i] = (i <= N) ? 1000000000 : (i - N);
            min_node[i] = i;
        }

        for (let i = 1; i <= M; i++) {
            let u = U[i], v = V[i];
            if (u === v) { prv[i] = i; continue; }
            makeroot(u);
            if (findroot(v) === u) {
                split(u, v);
                let j = val[min_node[v]]; prv[i] = j;
                safe_cut(U[j], N + j); safe_cut(V[j], N + j);
                safe_link(u, N + i); safe_link(v, N + i);
            } else {
                prv[i] = 0;
                safe_link(u, N + i); safe_link(v, N + i);
            }
        }

        function add(idx, v) { while (idx <= M + 1) { bit[idx] += v; idx += idx & -idx; } }
        function query(idx) { let sum = 0; while (idx > 0) { sum += bit[idx]; idx -= idx & -idx; } return sum; }

        let ans = new Int32Array(Q);
        for (let i = 1; i <= M; i++) {
            add(prv[i] + 1, 1);
            let curr = q_head[i];
            while (curr !== 0) {
                // CORRECTED FORMULA
                ans[q_id[curr]] = N - query(q_L[curr]) + q_L[curr] - 1;
                curr = q_next[curr];
            }
        }

        for (let i = 0; i < Q; i++) {
            out.push(ans[i]);
            if (out.length >= 50000) { process.stdout.write(out.join('\n') + '\n'); out.length = 0; }
        }
    }
    if (out.length > 0) process.stdout.write(out.join('\n') + '\n');
}

solve();
